import React, { Component } from 'react';
import { withRouter, Link } from 'react-router-dom';
import axios from 'axios';
import s from './Categories.module.scss';

class Categories extends Component {

    constructor(props) {
        super(props);
        this.state = {
            categories: [1]
        };
    }

    componentDidMount() {

    }

    render() {
        return (
            <main className={s.main}>
                <div className={s.featured}>
                    <div className={s.bstitle}>
                        <h3 className="bs-title">Popularne</h3>
                    </div>
                    <div className={s['featured__soon']}>
                        <p>Tutaj będą najwięcej wyświetlane / oglądane posty</p>
                    </div>
                </div>
                <div className={s.categories}>
                    <div className={[s['bstitle'], s['bstitle__action']].join(' ')}>
                        <h3 className="bs-title">Kategorie</h3>
                        <button>Zaproponuj nową</button>
                    </div>
                    <div className={s.ctgrid}>
                        {this.state.categories.map((obj, key) => <div className={s['ctgrid-item']}>
                            <Link to="/kategorie">
                                <div className={s['ctgrid-item__overlay']}>
                                    <div className={s['ctgrid-item__name']}>
                                        <h5>Sport & rekreacja</h5>
                                        {/* <p>4 Publikacje</p> */}
                                    </div>
                                </div>
                            </Link>
                        </div>)}
                    </div>
                </div>
            </main>
        )
    }
}

export default withRouter(Categories);
